import os
from typing import Optional

class Config:
    def __init__(self):
        self.schema_name = os.getenv('POSTGRES_SCHEMA', 'public')

class Database:
    def __init__(self, config: Config):
        self.config = config
        self.connection_string = self._build_connection_string()

    def _build_connection_string(self) -> str:
        return f"postgresql://user:password@localhost:5432/mydatabase?search_path={self.config.schema_name}"

def solve(*args):
    config = Config()
    db = Database(config)
    return db.connection_string
